<?php
$root=dirname(__DIR__);function ok($c,$m){if(!$c){fwrite(STDERR,"FAIL: $m\n");exit(1);}}
$required=array('sustainable-catalyst-lab.php','includes/class-sc-lab-plugin.php','includes/class-sc-lab-feeds.php','includes/class-sc-lab-rest.php','templates/lab-app.php','assets/css/sc-lab-app.css','assets/js/sc-lab-app.js','assets/js/modules/workspace.js','assets/js/modules/datasets.js','assets/js/modules/observations.js','contracts/project.schema.json');foreach($required as $f)ok(is_file($root.'/'.$f),"Missing $f");
$main=file_get_contents($root.'/sustainable-catalyst-lab.php');ok(strpos($main,'Version: 0.2.0')!==false,'Version marker missing');ok(strpos($main,"define('SC_LAB_VERSION', '0.2.0')")!==false,'Version constant missing');
$elements=json_decode(file_get_contents($root.'/assets/data/elements.json'),true);ok(is_array($elements)&&count($elements)===118,'Periodic table must contain 118 elements');
$feeds=file_get_contents($root.'/includes/class-sc-lab-feeds.php');foreach(array('usgs-earthquakes','nasa-eonet','nasa-space-telescopes','obis-marine','pubmed-science','arxiv-physics') as $source)ok(strpos($feeds,"'$source'")!==false,"Missing source $source");
$template=file_get_contents($root.'/templates/lab-app.php');foreach(array('Scientific signal board','Climate and Earth observation map','Space telescope observations','Marine biodiversity observations','Scientific dataset inspector','Scientific source registry','Chemistry workspace','Science and engineering tools') as $h)ok(strpos($template,$h)!==false,"Missing interface heading $h");ok(substr_count($template,'data-lab-module=')>=15,'Expected at least 15 module panels');foreach(array('data-dataset-table','data-dataset-chart','data-source-registry','data-climate-opacity','data-space-telescope','data-marine-summary') as $m)ok(strpos($template,$m)!==false,"Missing v0.2.0 marker $m");
$schema=json_decode(file_get_contents($root.'/contracts/project.schema.json'),true);ok(($schema['properties']['schemaVersion']['const']??'')==='0.2.0','Schema version incorrect');foreach(array('datasets','observations','savedQueries','sourceSnapshots','citations','mapViews') as $k)ok(isset($schema['properties'][$k]),"Missing project collection $k");echo "PHP structural tests passed.\n";
